import { execFileSync } from "node:child_process";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

type BeforeAllContext = {
  suite: Record<string, unknown>;
};

export function beforeAll(context: BeforeAllContext): BeforeAllContext {
  const scriptDir = dirname(fileURLToPath(import.meta.url));
  const python = process.env.PROMPTFOO_PR679_PYTHON ?? "python3";
  const materializer = resolve(scriptDir, "materialize_cargowise_workspace.py");
  const workspaceConfig = resolve(scriptDir, "..", "workspace.yaml");

  const stdout = execFileSync(
    python,
    [materializer, "--workspace-config", workspaceConfig],
    {
      encoding: "utf8",
      stdio: ["ignore", "pipe", "inherit"],
    },
  );
  const manifest = JSON.parse(stdout);

  process.env.PROMPTFOO_PR679_WORKSPACE_DIR = manifest.workspace_dir;
  process.env.PROMPTFOO_PR679_WORKSPACE_MANIFEST = manifest.manifest_path;

  return context;
}

