from __future__ import annotations

import json
import os
import subprocess
import urllib.error
import urllib.request
from pathlib import Path
from typing import Any

from materialize_cargowise_workspace import materialize_workspace, resolve_workspace_dir


SCRIPT_DIR = Path(__file__).resolve().parent
DEFAULT_API_BASE_URL = "http://127.0.0.1:10531/v1"
DEFAULT_MODEL = "gpt-5.3-codex-spark"
DEFAULT_PI_COMMAND = "pi"
DEFAULT_PI_PROVIDER = "promptfoo-local-openai"
DEFAULT_PI_EXTENSION = SCRIPT_DIR / "pi_local_openai_provider.ts"
DEFAULT_PI_TOOLS = "read,grep,find,ls"
DEFAULT_PI_THINKING = "low"


def _config(options: dict[str, Any]) -> dict[str, Any]:
    config = options.get("config", {})
    if not isinstance(config, dict):
        return {}
    return config


def _config_value(config: dict[str, Any], key: str, default: str | None = None) -> str | None:
    env_key = config.get(f"{key}Env")
    if isinstance(env_key, str) and os.environ.get(env_key):
        return os.environ[env_key]
    value = config.get(key)
    if isinstance(value, str) and value:
        return value
    return default


def _config_values(config: dict[str, Any], key: str) -> list[str]:
    values = config.get(key)
    if isinstance(values, str) and values:
        return [values]
    if isinstance(values, list) and all(isinstance(value, str) and value for value in values):
        return values
    return []


def _chat_completions_url(api_base_url: str) -> str:
    base = api_base_url.rstrip("/")
    if base.endswith("/chat/completions"):
        return base
    return f"{base}/chat/completions"


def _workspace_context(manifest: dict[str, Any]) -> str:
    repos = {repo.get("name") or repo.get("repo"): repo for repo in manifest["repos"]}
    return "\n".join(
        [
            "Local CargoWise workspace:",
            f"- CargoWise: {repos['CargoWise']['path']}",
            f"- CargoWise.Shared: {repos['CargoWise.Shared']['path']}",
            "- CargoWise.Shared contains schema files such as JobConsolTransport.sql.",
        ]
    )


def _load_or_materialize_workspace(config: dict[str, Any]) -> dict[str, Any]:
    manifest_path_value = _config_value(config, "workspaceManifest")
    if manifest_path_value:
        manifest_path = Path(manifest_path_value).expanduser()
        if manifest_path.exists():
            return json.loads(manifest_path.read_text(encoding="utf-8"))
    return materialize_workspace(workspace_dir=resolve_workspace_dir(_config_value(config, "workspaceDir")))


def _call_pi_cli(prompt: str, options: dict[str, Any]) -> dict[str, Any]:
    config = _config(options)
    manifest = _load_or_materialize_workspace(config)
    workspace_dir = Path(manifest["workspace_dir"])
    session_dir = Path(
        _config_value(config, "piSessionDir", str(workspace_dir / ".promptfoo-pi-sessions"))
        or str(workspace_dir / ".promptfoo-pi-sessions")
    ).expanduser()
    if not session_dir.is_absolute():
        session_dir = workspace_dir / session_dir
    session_dir.mkdir(parents=True, exist_ok=True)

    pi_command = _config_value(config, "piCommand", DEFAULT_PI_COMMAND) or DEFAULT_PI_COMMAND
    pi_provider = _config_value(config, "piProvider", DEFAULT_PI_PROVIDER) or DEFAULT_PI_PROVIDER
    model = _config_value(config, "model", DEFAULT_MODEL) or DEFAULT_MODEL
    pi_extension_path = Path(
        _config_value(config, "piExtension", str(DEFAULT_PI_EXTENSION)) or str(DEFAULT_PI_EXTENSION)
    ).expanduser()
    if not pi_extension_path.is_absolute():
        pi_extension_path = SCRIPT_DIR.parent / pi_extension_path
    pi_tools = _config_value(config, "piTools", DEFAULT_PI_TOOLS) or DEFAULT_PI_TOOLS
    pi_thinking = _config_value(config, "piThinking", DEFAULT_PI_THINKING) or DEFAULT_PI_THINKING
    pi_skills = _config_values(config, "piSkills")

    agent_prompt = f"{_workspace_context(manifest)}\n\n{prompt}"
    cmd = [
        pi_command,
        "-p",
        "--approve",
        "--extension",
        str(pi_extension_path),
        "--provider",
        pi_provider,
        "--model",
        model,
        "--thinking",
        pi_thinking,
        "--session-dir",
        str(session_dir),
        "--no-skills",
        "--no-prompt-templates",
        "--no-themes",
    ]
    for skill in pi_skills:
        cmd.extend(["--skill", skill])
    cmd.extend(
        [
            "--tools",
            pi_tools,
            agent_prompt,
        ]
    )
    metadata: dict[str, Any] = {
        "provider": "pi-cli",
        "piProvider": pi_provider,
        "model": model,
        "workspace": manifest,
        "piSessionDir": session_dir.as_posix(),
    }
    timeout = float(config.get("piTimeout", 900))
    env = os.environ.copy()
    api_base_url = _config_value(config, "apiBaseUrl")
    if api_base_url:
        env["PROMPTFOO_PI_CLI_BASE_URL"] = api_base_url
    api_key = _config_value(config, "apiKey")
    if api_key:
        env["PROMPTFOO_PI_CLI_API_KEY"] = api_key

    try:
        result = subprocess.run(
            cmd,
            cwd=workspace_dir,
            text=True,
            stdin=subprocess.DEVNULL,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=timeout,
            env=env,
        )
    except subprocess.TimeoutExpired as exc:
        return {
            "error": f"pi CLI timed out after {timeout:g} seconds",
            "metadata": {
                **metadata,
                "stdout": exc.stdout,
                "stderr": exc.stderr,
            },
        }

    output = result.stdout.strip()
    if result.returncode != 0:
        return {
            "error": f"pi CLI exited with status {result.returncode}: {result.stderr.strip()}",
            "metadata": {
                **metadata,
                "stdout": output,
                "stderr": result.stderr.strip(),
            },
        }

    return {
        "output": output,
        "metadata": {
            **metadata,
            "stderr": result.stderr.strip(),
        },
    }


def _call_local_openai(prompt: str, options: dict[str, Any]) -> dict[str, Any]:
    config = _config(options)
    api_base_url = _config_value(config, "apiBaseUrl", DEFAULT_API_BASE_URL)
    if api_base_url is None:
        raise ValueError("apiBaseUrl could not be resolved")
    model = _config_value(config, "model", DEFAULT_MODEL)
    if model is None:
        raise ValueError("model could not be resolved")

    messages: list[dict[str, str]] = []
    metadata: dict[str, Any] = {
        "apiBaseUrl": api_base_url,
        "model": model,
        "provider": "local-openai-grader",
    }

    messages.append({"role": "user", "content": prompt})
    payload = {
        "model": model,
        "messages": messages,
    }
    if "temperature" in config:
        payload["temperature"] = config["temperature"]
    for key in ("max_tokens", "max_completion_tokens", "top_p", "seed"):
        if key in config:
            payload[key] = config[key]

    body = json.dumps(payload).encode("utf-8")
    headers = {"Content-Type": "application/json"}
    api_key = _config_value(config, "apiKey")
    if api_key:
        headers["Authorization"] = f"Bearer {api_key}"

    request = urllib.request.Request(
        _chat_completions_url(api_base_url),
        data=body,
        headers=headers,
        method="POST",
    )
    timeout = float(config.get("timeout", 600))
    try:
        with urllib.request.urlopen(request, timeout=timeout) as response:
            response_payload = json.loads(response.read().decode("utf-8"))
    except urllib.error.URLError as exc:
        return {
            "error": f"Could not reach local pi-cli OpenAI-compatible endpoint at {api_base_url}: {exc}",
