            "total": usage.get("total_tokens"),
            "prompt": usage.get("prompt_tokens"),
            "completion": usage.get("completion_tokens"),
        }
    return {
        "output": output,
        "tokenUsage": token_usage,
        "metadata": metadata,
    }


