    command,
    ...(hook.timeout_ms !== undefined && { timeout_ms: hook.timeout_ms }),
    ...(hook.timeoutMs !== undefined && { timeoutMs: hook.timeoutMs }),
    ...(hook.cwd !== undefined && { cwd: hook.cwd }),
    ...(hook.script !== undefined && { script: hook.script }),
